import os, shutil, collections

# Dirs to flatten
dirs = ['Facet', 'Frieze', 'IMAGES', 'INBOX', 'Inlay', 'Statue', 'tags', 'TOPICS']

# Check for collisions first
all_files = []
for d in dirs:
    if os.path.isdir(d):
        for f in os.listdir(d):
            fp = os.path.join(d, f)
            if os.path.isfile(fp):
                all_files.append((d, f))

names = [f for _, f in all_files]
counts = collections.Counter(names)
collisions = {n: c for n, c in counts.items() if c > 1}
if collisions:
    print("COLLISIONS:", collisions)
else:
    print("No collisions — safe to proceed")
    print(f"Total files to move: {len(all_files)}")
    for d, f in all_files:
        print(f"  {d}/{f}")
